INSERT INTO products (id, category_id, name, slug, description, is_active, created_by) VALUES
('2ff8a99c-44c0-4591-814a-5867d021aaca', '0ce6d0b6-a04a-4ff2-8866-81989d795141', 'Apple iPhone 15 Pro', 'apple-iphone-15-pro', 'Forged in titanium with A17 Pro chip, customizable Action button, and the most powerful iPhone camera system ever.', TRUE, 'system'),
('d01b8c22-b90d-4695-81d7-28d29a0d4b5e', '0ce6d0b6-a04a-4ff2-8866-81989d795141', 'Samsung Galaxy S24 Ultra', 'samsung-galaxy-s24-ultra', 'Built-in S Pen, 200MP camera, Snapdragon 8 Gen 3, and 5000mAh battery. The ultimate Android flagship.', TRUE, 'system'),
('d3164da5-e630-4a0c-ac6d-dfc7b66f3b07', '0ce6d0b6-a04a-4ff2-8866-81989d795141', 'Sony WH-1000XM5 Wireless Headphones', 'sony-wh-1000xm5', 'Industry-leading noise canceling, 30-hour battery life, and crystal clear hands-free calling.', TRUE, 'system'),
('1851573e-f8f9-414c-98d3-5bc3a01e8b0b', '0ce6d0b6-a04a-4ff2-8866-81989d795141', 'Apple MacBook Pro 14-inch M3', 'apple-macbook-pro-14-m3', 'M3 chip, up to 22 hours battery life, Liquid Retina XDR display for the most demanding workflows.', TRUE, 'system'),
('14dc71ff-8f05-4253-aa77-48a8fea12948', '0ce6d0b6-a04a-4ff2-8866-81989d795141', 'iPad Pro 12.9-inch M2', 'apple-ipad-pro-12-9-m2', 'M2 chip, Liquid Retina XDR display, Center Stage, and pro camera system with LiDAR Scanner.', TRUE, 'system'),
('a3a336b7-e33d-428c-9c7b-f4aa3b3121d5', '7975b161-6fb3-451c-b52f-f34b82f22336', 'Atomic Habits by James Clear', 'atomic-habits-james-clear', 'An easy and proven way to build good habits and break bad ones. Over 10 million copies sold worldwide.', TRUE, 'system'),
('24f96f52-e17f-4426-9c4a-50f9e5e84d72', '7975b161-6fb3-451c-b52f-f34b82f22336', 'The Pragmatic Programmer 20th Anniversary', 'pragmatic-programmer-20th-anniversary', 'Your journey to mastery. Essential reading for software developers at every experience level.', TRUE, 'system'),
('49e1c006-a927-46cf-b44d-727ac24f30dc', '7975b161-6fb3-451c-b52f-f34b82f22336', 'Clean Code by Robert C. Martin', 'clean-code-robert-martin', 'A handbook of agile software craftsmanship. Learn to write code that is readable, maintainable and efficient.', TRUE, 'system'),
('6ca543af-f13e-456d-a4b3-3c5fa1501191', '7975b161-6fb3-451c-b52f-f34b82f22336', 'Designing Data-Intensive Applications', 'designing-data-intensive-applications', 'The big ideas behind reliable, scalable, and maintainable systems. A must-read for backend engineers.', TRUE, 'system'),
('2b3f1d85-0c16-496e-b9fd-af02e6973b3d', '7975b161-6fb3-451c-b52f-f34b82f22336', 'The Psychology of Money', 'psychology-of-money-morgan-housel', 'Timeless lessons on wealth, greed, and happiness by Morgan Housel. Over 4 million copies sold.', TRUE, 'system'),
('081ab306-f43c-401b-97e5-7c7cc8c83b31', '4df3dcd5-b1de-4971-b72f-2124910634a5', 'Levi''s 501 Original Fit Jeans', 'levis-501-original-fit-jeans', 'The original blue jean since 1873. Straight fit with button fly, sits at the waist.', TRUE, 'system'),
('35b65fe8-efa1-4bcf-a129-34a8bd5a675a', '4df3dcd5-b1de-4971-b72f-2124910634a5', 'Nike Air Force 1 Sneakers', 'nike-air-force-1-sneakers', 'Iconic street style sneakers with Air-Sole unit for all-day lightweight cushioning and comfort.', TRUE, 'system'),
('dfdece05-59ce-48d4-ba22-7d44bba16734', '4df3dcd5-b1de-4971-b72f-2124910634a5', 'Champion Reverse Weave Hoodie', 'champion-reverse-weave-hoodie', 'Classic heavyweight fleece hoodie with iconic C logo patch. Resists vertical shrinkage.', TRUE, 'system'),
('5e0ef7ac-1352-46b6-904c-66c298ce12df', '4df3dcd5-b1de-4971-b72f-2124910634a5', 'Adidas Ultraboost 22 Running Shoes', 'adidas-ultraboost-22', 'Responsive BOOST midsole and Primeknit+ upper for an energized, adaptive run every time.', TRUE, 'system'),
('cf0b285b-00d8-485a-8cd9-9becfea9f053', '4df3dcd5-b1de-4971-b72f-2124910634a5', 'The North Face Antora Rain Jacket', 'north-face-antora-rain-jacket', 'Waterproof, breathable DryVent 2.5L shell keeps you dry and comfortable in wet conditions.', TRUE, 'system'),
('eac538e9-94dd-45b7-93bf-5a5333fc2281', 'e50bd3d8-7ae9-4207-907d-b3b3e7c6555c', 'Instant Pot Duo 7-in-1 Electric Pressure Cooker', 'instant-pot-duo-7-in-1', 'Pressure cooker, slow cooker, rice cooker, steamer, saute pan, yogurt maker and warmer in one.', TRUE, 'system'),
('b1f7fd8f-10c5-4cdf-923b-3fe56efd1c02', 'e50bd3d8-7ae9-4207-907d-b3b3e7c6555c', 'Dyson V15 Detect Cordless Vacuum', 'dyson-v15-detect-cordless-vacuum', 'Laser reveals microscopic dust. Automatically adapts suction to floor type with 60 minutes run time.', TRUE, 'system'),
('9ddf600c-d32e-4541-955e-e21ee2f7e1ec', 'e50bd3d8-7ae9-4207-907d-b3b3e7c6555c', 'Nespresso Vertuo Next Coffee Machine', 'nespresso-vertuo-next', 'Brew 5 cup sizes from espresso to alto with one-touch brewing and automatic capsule recognition.', TRUE, 'system'),
('464636b6-7e23-49e8-811a-dce15ad8a585', 'e50bd3d8-7ae9-4207-907d-b3b3e7c6555c', 'KitchenAid Artisan Stand Mixer 5Qt', 'kitchenaid-artisan-stand-mixer-5qt', '10 speeds, tilt-head design, 5-quart stainless steel bowl. The iconic kitchen essential.', TRUE, 'system'),
('ea4e1c77-9931-4303-9fe9-fe3b39f4977d', 'e50bd3d8-7ae9-4207-907d-b3b3e7c6555c', 'Philips Hue Smart Bulb Starter Kit', 'philips-hue-smart-bulb-starter-kit', '4 A19 smart LED bulbs and Bridge. 16 million colors, voice control and app-based automation.', TRUE, 'system'),
('a99d062d-cbaa-4d5d-b8b3-e51bfcec40b9', '4e9b0ba5-9829-43b1-9dba-91f4a1cee9bc', 'Garmin Fenix 7 Multisport GPS Watch', 'garmin-fenix-7-multisport-gps', 'Rugged smartwatch with multi-band GPS, solar charging, heart rate, and over 60 sport modes.', TRUE, 'system'),
('997a1b6e-5e35-4837-9ce0-18e28ff7a95b', '4e9b0ba5-9829-43b1-9dba-91f4a1cee9bc', 'Hydro Flask 32oz Wide Mouth Water Bottle', 'hydro-flask-32oz-wide-mouth', 'TempShield double-wall vacuum insulation keeps drinks cold 24 hours, hot 12 hours.', TRUE, 'system'),
('2a98ce96-85b2-4b73-b7a1-2da0b1175ddb', '4e9b0ba5-9829-43b1-9dba-91f4a1cee9bc', 'Theragun Prime Percussive Therapy Device', 'theragun-prime-percussive-therapy', 'Quiet Force Technology, 5 attachments, 16mm amplitude for deep muscle treatment in 30 seconds.', TRUE, 'system'),
('2db09b98-ebbd-4558-9e52-6a57a94aeb5f', '4e9b0ba5-9829-43b1-9dba-91f4a1cee9bc', 'Coleman Sundome 4-Person Camping Tent', 'coleman-sundome-4-person-tent', 'Easy setup in 10 minutes, WeatherTec patented welded floors and inverted seams keep you dry.', TRUE, 'system'),
('f02f296c-546a-4606-bf3a-b3083b7fef43', '4e9b0ba5-9829-43b1-9dba-91f4a1cee9bc', 'Manduka PRO Yoga Mat 6mm', 'manduka-pro-yoga-mat-6mm', 'Lifetime guarantee, high-density cushioning, non-slip surface, closed-cell material resists bacteria.', TRUE, 'system');
